package main
import (
    "fmt"
    "net/http"

    "github.com/prometheus/client_golang/prometheus"
    "github.com/prometheus/client_golang/prometheus/promauto"
    "github.com/prometheus/client_golang/prometheus/promhttp"
)
func main() {
    http.Handle("/metrics", promhttp.Handler())

    userCounter := promauto.NewCounterVec(
        prometheus.CounterOpts{
            Name: "user_count",
            Help: "Total number of users",
        }, []string{"user"},
    )

    requestCounter := promauto.NewCounterVec(
        prometheus.CounterOpts{
            Name: "request_count",
            Help: "Total number of requests",
        }, []string{"method", "path"},
    )

    http.HandleFunc("/metrics/user/", func(w http.ResponseWriter, r *http.Request) {
        user := r.URL.Path[len("/metrics/user/"):]

        userCounter.WithLabelValues(user).Inc()

        fmt.Fprintf(w, "%s\n", user)
    })

    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
        requestCounter.WithLabelValues("GET", "/").Inc()

        fmt.Fprintf(w, "Hello World!\n")
    })

    http.ListenAndServe(":8080", nil)
}